import{_ as e,o as a,c as d,a2 as r}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"Page Settings","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Page/page-settings.md","filePath":"ta/Page/page-settings.md","lastUpdated":1781962217000}'),o={name:"ta/Page/page-settings.md"};function i(n,t,l,g,s,c){return a(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="page-settings" tabindex="-1">Page Settings <a class="header-anchor" href="#page-settings" aria-label="Permalink to &quot;Page Settings&quot;">​</a></h1><p>Page settings site display, upload page defaults, background images, admin panel appearance ஆகியவற்றை கட்டுப்படுத்தும்.</p><h2 id="global-settings" tabindex="-1">Global Settings <a class="header-anchor" href="#global-settings" aria-label="Permalink to &quot;Global Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Site title</td><td>browser tab-ல் காட்டப்படும் title.</td></tr><tr><td>Site icon</td><td>browser tab-ல் காட்டப்படும் சிறிய icon.</td></tr><tr><td>ImgBed name</td><td>frontend pages-ல் காட்டப்படும் பெயர்.</td></tr><tr><td>ImgBed logo</td><td>frontend pages-ல் காட்டப்படும் logo image.</td></tr><tr><td>Logo link</td><td>logo அல்லது avatar click செய்தால் திறக்கும் URL.</td></tr><tr><td>Background switch interval</td><td>multiple backgrounds rotation interval, milliseconds. <code>60000</code> = 60 seconds.</td></tr><tr><td>Background opacity</td><td>background image opacity <code>0</code> முதல் <code>1</code> வரை. குறைந்த value image-ஐ lighter ஆக்கும்.</td></tr><tr><td>Default URL prefix</td><td>image links generate செய்யும் போது பயன்படுத்தும் prefix. empty என்றால் current site domain.</td></tr></tbody></table><h2 id="client-settings" tabindex="-1">Client Settings <a class="header-anchor" href="#client-settings" aria-label="Permalink to &quot;Client Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Announcement</td><td>upload page மேல் காட்டப்படும் announcement. HTML supported.</td></tr><tr><td>Default upload channel</td><td>upload page-ல் default selected upload channel. Smart Dispatch தேர்வு செய்யலாம்.</td></tr><tr><td>Default upload directory</td><td>default upload directory, உதா. <code>/user/</code>. empty அல்லது <code>/</code> என்றால் root.</td></tr><tr><td>Default naming method</td><td>upload பிறகு default filename generation strategy. கீழே பார்க்கவும்.</td></tr><tr><td>Convert to WebP by default</td><td>upload முன் images-ஐ WebP-க்கு convert.</td></tr><tr><td>Enable compression by default</td><td>upload முன் browser-ல் images locally compress.</td></tr><tr><td>Default compression threshold</td><td>image இந்த size-ஐ மீறினால் automatically compress, MB.</td></tr><tr><td>Default target size</td><td>compression பிறகு target file size, MB.</td></tr><tr><td>Login page background</td><td>user login page background image.</td></tr><tr><td>Upload page background</td><td>upload page background image.</td></tr><tr><td>Footer portal link</td><td>footer portal button திறக்கும் URL.</td></tr><tr><td>Hide footer</td><td>enabled என்றால் frontend footer hide.</td></tr></tbody></table><h2 id="admin-settings" tabindex="-1">Admin Settings <a class="header-anchor" href="#admin-settings" aria-label="Permalink to &quot;Admin Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Purpose</th></tr></thead><tbody><tr><td>Admin login background</td><td>admin login page background image.</td></tr><tr><td>Admin background</td><td>admin pages background image. ஒரு image URL அல்லது multiple URLs.</td></tr><tr><td>Image loading mode</td><td>admin file list preview loading mode. Original original images load செய்யும். Smart loading public images-க்கு thumbnails, restricted images-க்கு originals prefer செய்யும்.</td></tr><tr><td>Thumbnail source</td><td>thumbnails generate செய்யும் service: wsrv.nl, Cloudflare Image Resizing, WordPress Photon. Cloudflare Image Resizing தேர்வு செய்ய முன் Cloudflare-ல் enable செய்ய வேண்டும்.</td></tr><tr><td>Live2D widget</td><td>admin panel-ல் Live2D character காட்டும்.</td></tr><tr><td>Firework click effect</td><td>page click செய்தால் firework effect.</td></tr><tr><td>Star cursor trail</td><td>mouse move செய்தால் star trail.</td></tr></tbody></table><h2 id="background-image-formats" tabindex="-1">Background Image Formats <a class="header-anchor" href="#background-image-formats" aria-label="Permalink to &quot;Background Image Formats&quot;">​</a></h2><p>Login page background, upload page background, admin login background இந்த formats support செய்கின்றன:</p><table tabindex="0"><thead><tr><th>Value</th><th>Effect</th></tr></thead><tbody><tr><td><code>bing</code></td><td>Bing wallpaper rotation பயன்படுத்தும்.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;,&quot;https://example.com/2.jpg&quot;]</code></td><td>multiple images rotate.</td></tr><tr><td><code>[&quot;https://example.com/1.jpg&quot;]</code></td><td>single background image.</td></tr><tr><td><code>[&quot;https://your-domain.com/random?...&quot;]</code></td><td>random image API link. Other Settings-ல் உங்கள் Random Image API configure செய்து generated random image link-ஐ single-background entry ஆக paste செய்யலாம்.</td></tr></tbody></table><p>admin background image URLs support செய்கிறது. page prompt படி multiple URLs English commas மூலம் separate செய்யலாம். empty என்றால் default background.</p><h2 id="default-naming-method" tabindex="-1">Default Naming Method <a class="header-anchor" href="#default-naming-method" aria-label="Permalink to &quot;Default Naming Method&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Result</th></tr></thead><tbody><tr><td>Default</td><td>time-random prefix + original filename, உதா. <code>1760000000000_cat.png</code>.</td></tr><tr><td>Prefix only</td><td>time-random prefix மற்றும் extension மட்டும், உதா. <code>1760000000000.png</code>.</td></tr><tr><td>Original name only</td><td>original filename வைத்திருக்கும், உதா. <code>cat.png</code>. duplicate என்றால் ImgBed <code>(1)</code>, <code>(2)</code> போன்றவை சேர்க்கும்.</td></tr><tr><td>Short link</td><td>8-character short ID மற்றும் extension, உதா. <code>a1b2c3d4.png</code>.</td></tr></tbody></table>',14)])])}const u=e(o,[["render",i]]);export{p as __pageData,u as default};
